class LoggingOkHttpInterceptor : okhttp3.Interceptor {
    override fun intercept(chain: okhttp3.Interceptor.Chain): okhttp3.Response {
        val request = chain.request()
        val requestId = UUID.randomUUID().toString()
        val startNs = System.nanoTime()

        val requestBodyString = request.body?.let { body ->
            runCatching {
                val buffer = okio.Buffer()
                body.writeTo(buffer)
                buffer.readUtf8()
            }.getOrNull()
        }

        AppLogger.logApiRequest(
            method = request.method,
            url = request.url.toString(),
            headers = request.headers.toMap(),
            body = requestBodyString,
            requestId = requestId
        )

        return try {
            val response = chain.proceed(request)
            val tookMs = (System.nanoTime() - startNs) / 1_000_000
            val responseBodyString = response.peekBody(Long.MAX_VALUE).string()
            AppLogger.logApiResponse(
                method = request.method,
                url = request.url.toString(),
                code = response.code,
                headers = response.headers.toMap(),
                body = responseBodyString,
                requestId = requestId,
                durationMs = tookMs
            )
            response
        } catch (e: Exception) {
            val tookMs = (System.nanoTime() - startNs) / 1_000_000
            AppLogger.logException(
                tag = "API",
                throwable = e,
                contextMessage = "API request failed, requestId=$requestId, method=${request.method}, url=${request.url}, durationMs=$tookMs"
            )
            throw e
        }
    }
}

fun Map<String, String>.toMap(): Map<String, String> = this.entries.associate { it.key to it.value }

