class GlobalExceptionHandler(
    private val previousHandler: Thread.UncaughtExceptionHandler? = Thread.getDefaultUncaughtExceptionHandler()
) : Thread.UncaughtExceptionHandler {
    override fun uncaughtException(thread: Thread, throwable: Throwable) {
        AppLogger.logException(
            tag = "UncaughtException",
            throwable = throwable,
            contextMessage = "Uncaught exception on thread=${thread.name}"
        )
        previousHandler?.uncaughtException(thread, throwable)
    }
}

fun Throwable.captureAndLog(tag: String = "Exception", message: String? = null): Throwable {
    AppLogger.logException(tag, this, message)
    return this
}

class LoggingInitializer(private val context: Context) {
    fun initialize(enableVerboseLogging: Boolean = true) {
        AppLogger.init(context, enableVerboseLogging)
        Thread.setDefaultUncaughtExceptionHandler(GlobalExceptionHandler())
    }
}

